class Solution {
    int m, n;
    int total;
    int[][] matrix;
    Random rand;

    public Solution(int m, int n) {
        this.m = m;
        this.n = m * n;
        this.total = m * n;
        this.matrix = new int[m][n];
        this.rand = new Random();
    }

    public int[] flip() {
        int idx = rand.nextInt(total);
        int i = 0;
        while (i < m) {
            int j = 0;
            while (j < n) {
                if (matrix[i][j] == 0) {
                    total--;
                    matrix[i][j] = 1;
                    if (total == idx) {
                        return new int[] {i, j};
                    }
                }
                j++;
            }
            i++;
        }
        return null;
    }

    public void reset() {
        total = m * n;
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                matrix[i][j] = 0;
            }
        }
    }
}
